"""
Plan schema — typed representation of PLAN.json.

Uses pydantic for validation, serialization, and deserialization.
"""

import json
import logging
from pathlib import Path
from typing import Optional

from pydantic import BaseModel, Field

logger = logging.getLogger(__name__)


class Task(BaseModel):
    """A single executable task within a phase."""
    id: str
    name: str
    description: str = ""
    files_to_create: list[str] = Field(default_factory=list)
    files_to_modify: list[str] = Field(default_factory=list)
    depends_on: list[str] = Field(default_factory=list)
    model: str = ""
    effort: str = ""
    test_level: str = ""  # "", "L1", "L2"
    convention_skills: list[str] = Field(default_factory=list)  # e.g. ["ruby-code-writing", "form-builder"]


class Phase(BaseModel):
    """A group of related tasks executed sequentially."""
    id: str
    name: str
    description: str = ""
    tasks: list[Task] = Field(default_factory=list)

    def model_post_init(self, __context):
        # Normalize: accept both "id" and "phase" field names
        if not self.id and hasattr(self, "phase"):
            self.id = str(getattr(self, "phase"))


class Plan(BaseModel):
    """The full execution plan for a dirigent run."""
    title: str = "Untitled"
    summary: str = ""
    phases: list[Phase] = Field(default_factory=list)
    estimated_complexity: str = "medium"
    risks: list[str] = Field(default_factory=list)
    assumptions: list[str] = Field(default_factory=list)
    out_of_scope: list[str] = Field(default_factory=list)

    @property
    def total_tasks(self) -> int:
        return sum(len(p.tasks) for p in self.phases)

    @property
    def all_tasks(self) -> list[tuple[Task, Phase]]:
        """Flat list of (task, phase) in execution order."""
        return [(t, p) for p in self.phases for t in p.tasks]

    def task_position(self, task_id: str) -> Optional[dict]:
        """Position info for a task: index, total, phase, prev/next."""
        tasks = self.all_tasks
        idx = next((i for i, (t, _) in enumerate(tasks) if t.id == task_id), None)
        if idx is None:
            return None

        t, p = tasks[idx]
        info = {
            "index": idx + 1,
            "total": len(tasks),
            "phase_id": p.id,
            "phase_name": p.name,
            "total_phases": len(self.phases),
        }
        if idx > 0:
            prev_t, _ = tasks[idx - 1]
            info["prev_id"] = prev_t.id
            info["prev_name"] = prev_t.name
        if idx < len(tasks) - 1:
            next_t, _ = tasks[idx + 1]
            info["next_id"] = next_t.id
            info["next_name"] = next_t.name
        return info

    def save(self, path: Path):
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(
            self.model_dump_json(indent=2, exclude_none=True),
            encoding="utf-8",
        )

    @classmethod
    def load(cls, path: Path) -> Optional["Plan"]:
        """Load from PLAN.json. Returns None if missing or invalid."""
        if not path.exists():
            return None
        try:
            raw = json.loads(path.read_text(encoding="utf-8"))
            # Normalize phase/task fields from common LLM output variations
            for p in raw.get("phases", []):
                if "phase" in p and "id" not in p:
                    p["id"] = str(p.pop("phase"))
                elif "id" in p:
                    p["id"] = str(p["id"])
                for t in p.get("tasks", []):
                    # title → name
                    if "title" in t and "name" not in t:
                        t["name"] = t.pop("title")
                    # files → files_to_modify (conservative default)
                    if "files" in t and "files_to_modify" not in t and "files_to_create" not in t:
                        t["files_to_modify"] = t.pop("files")
            return cls.model_validate(raw)
        except json.JSONDecodeError as e:
            logger.error("PLAN.json is not valid JSON: %s", e)
            return None
        except Exception as e:
            logger.error("PLAN.json validation failed: %s", e)
            return None

    @staticmethod
    def json_template() -> str:
        """JSON template string for the plan creation prompt."""
        return """{
  "title": "Feature-Titel",
  "summary": "Kurze Beschreibung was implementiert wird",
  "assumptions": [
    "Annahmen die du über die Codebase/das Feature machst",
    "z.B. 'Tests laufen mit pytest', 'API ist REST-basiert'"
  ],
  "out_of_scope": [
    "Was NICHT Teil dieses Plans ist",
    "z.B. 'Deployment/CI-Pipeline', 'Performance-Optimierung'"
  ],
  "phases": [
    {
      "id": "01",
      "name": "Phase-Name",
      "description": "Was in dieser Phase passiert",
      "tasks": [
        {
          "id": "01-01",
          "name": "Task-Name",
          "description": "Detaillierte Beschreibung was zu tun ist",
          "files_to_create": ["liste/von/neuen/dateien.ext"],
          "files_to_modify": ["liste/von/existierenden/dateien.ext"],
          "depends_on": [],
          "model": "sonnet|haiku|opus (welches Modell für diesen Task am besten ist)",
          "effort": "low|medium|high (wie viel Denkaufwand nötig ist)",
          "test_level": "L1|L2| (welches Test-Level nach diesem Task laufen soll, leer wenn kein Test nötig)",
          "convention_skills": ["skill-name-1", "skill-name-2 (aus .opencode/skills/, leer wenn keine)"]
        }
      ]
    }
  ],
  "estimated_complexity": "low|medium|high",
  "risks": ["Liste von potentiellen Risiken"]
}"""

#!/usr/bin/env python3
"""Validate Plan JSON. Standalone — stdlib only."""
import json
import re
import sys

VALID_MODELS = {"", "haiku", "sonnet", "opus"}
VALID_EFFORTS = {"", "low", "medium", "high"}
VALID_TEST_LEVELS = {"", "L1", "L2"}


def validate(path: str):
    errors = []
    warnings = []

    with open(path) as f:
        data = json.load(f)

    if not isinstance(data, dict):
        errors.append("Root must be a JSON object")
        return errors, warnings

    # Required: phases
    if "phases" not in data:
        errors.append("Missing required field: 'phases'")
        return errors, warnings

    phases = data["phases"]
    if not isinstance(phases, list):
        errors.append("'phases' must be a list")
        return errors, warnings

    if len(phases) < 1:
        errors.append("'phases' must have at least 1 item")

    all_task_ids = {}   # task_id -> "phase[i].tasks[j]" for uniqueness tracking
    phase_ids = {}      # phase_id -> "phases[i]" for uniqueness tracking
    depends_on_refs = []  # (ref_task_id, location_str) to validate after collecting all IDs

    for i, phase in enumerate(phases):
        pprefix = f"phases[{i}]"

        if not isinstance(phase, dict):
            errors.append(f"{pprefix}: must be an object")
            continue

        # phase.id
        if "id" not in phase:
            errors.append(f"{pprefix}: missing 'id'")
        elif not isinstance(phase["id"], str) or not phase["id"].strip():
            errors.append(f"{pprefix}.id: must be a non-empty string")
        else:
            pid = phase["id"]
            if pid in phase_ids:
                errors.append(f"{pprefix}.id: duplicate phase id '{pid}' (first seen at {phase_ids[pid]})")
            else:
                phase_ids[pid] = pprefix

        # phase.name
        if "name" not in phase:
            errors.append(f"{pprefix}: missing 'name'")
        elif not isinstance(phase["name"], str) or not phase["name"].strip():
            errors.append(f"{pprefix}.name: must be a non-empty string")

        # phase.tasks
        if "tasks" not in phase:
            errors.append(f"{pprefix}: missing 'tasks'")
            continue

        tasks = phase["tasks"]
        if not isinstance(tasks, list):
            errors.append(f"{pprefix}.tasks: must be a list")
            continue

        if len(tasks) < 1:
            errors.append(f"{pprefix}.tasks: must have at least 1 task")

        for j, task in enumerate(tasks):
            tprefix = f"{pprefix}.tasks[{j}]"

            if not isinstance(task, dict):
                errors.append(f"{tprefix}: must be an object")
                continue

            # task.id
            if "id" not in task:
                errors.append(f"{tprefix}: missing 'id'")
            elif not isinstance(task["id"], str) or not task["id"].strip():
                errors.append(f"{tprefix}.id: must be a non-empty string")
            else:
                tid = task["id"]
                if tid in all_task_ids:
                    errors.append(f"{tprefix}.id: duplicate task id '{tid}' (first seen at {all_task_ids[tid]})")
                else:
                    all_task_ids[tid] = tprefix

            # task.name
            if "name" not in task:
                errors.append(f"{tprefix}: missing 'name'")
            elif not isinstance(task["name"], str) or not task["name"].strip():
                errors.append(f"{tprefix}.name: must be a non-empty string")

            # Optional: model
            if "model" in task:
                if not isinstance(task["model"], str):
                    errors.append(f"{tprefix}.model: must be a string")
                elif task["model"] not in VALID_MODELS:
                    errors.append(f"{tprefix}.model: '{task['model']}' must be one of {sorted(VALID_MODELS)}")

            # Optional: effort
            if "effort" in task:
                if not isinstance(task["effort"], str):
                    errors.append(f"{tprefix}.effort: must be a string")
                elif task["effort"] not in VALID_EFFORTS:
                    errors.append(f"{tprefix}.effort: '{task['effort']}' must be one of {sorted(VALID_EFFORTS)}")

            # Optional: test_level
            if "test_level" in task:
                if not isinstance(task["test_level"], str):
                    errors.append(f"{tprefix}.test_level: must be a string")
                elif task["test_level"] not in VALID_TEST_LEVELS:
                    errors.append(f"{tprefix}.test_level: '{task['test_level']}' must be one of {sorted(VALID_TEST_LEVELS)}")

            # Optional: depends_on
            if "depends_on" in task:
                deps = task["depends_on"]
                if not isinstance(deps, list):
                    errors.append(f"{tprefix}.depends_on: must be a list")
                else:
                    for dep in deps:
                        if not isinstance(dep, str):
                            errors.append(f"{tprefix}.depends_on: each item must be a string, got {type(dep).__name__}")
                        else:
                            depends_on_refs.append((dep, tprefix))

    # Validate depends_on refs point to existing task IDs
    for ref_id, location in depends_on_refs:
        if ref_id not in all_task_ids:
            errors.append(f"{location}.depends_on: references unknown task id '{ref_id}'")

    return errors, warnings


def main():
    if len(sys.argv) != 2:
        print(f"Usage: {sys.argv[0]} <json-file>", file=sys.stderr)
        sys.exit(1)
    try:
        errors, warnings = validate(sys.argv[1])
    except json.JSONDecodeError as e:
        print(f"VALIDATION FAILED: Invalid JSON: {e}")
        sys.exit(1)
    except FileNotFoundError:
        print(f"VALIDATION FAILED: File not found: {sys.argv[1]}")
        sys.exit(1)
    for w in warnings:
        print(f"  WARNING: {w}")
    if errors:
        print(f"VALIDATION FAILED ({len(errors)} errors):")
        for e in errors:
            print(f"  ERROR: {e}")
        sys.exit(1)
    print("VALIDATION PASSED")
    sys.exit(0)


if __name__ == "__main__":
    main()

